assistant: To address the comment "Please add locationId to post and put requests in events", you can modify the EventDto class to include a locationId property:

```ts
export class EventDto {
  id: number;
  name: string;
  color: number;
  date: Date;
  locationId: number; // add this property
}
```

Then, when creating or updating an event, you can include the locationId in the request body:

```json
{
  "name": "Event Name",
  "color": 123,
  "date": "2022-01-01",
  "locationId": 1
}
```

In your controller, you can access the locationId property and assign it to the event's location:

```ts
async createEvent(@Body() body: EventDto): Promise<EventDto> {
  const event = new EventEntity();
  event.name = body.name;
  event.color = body.color;
  event.date = body.date;
  event.location = await this.locationRepository.findOne(body.locationId);
  await this.eventRepository.save(event);
  return event.toDto();
}
```

Similarly, for updating an event, you can modify the event entity before saving it:

```ts
async updateEvent(@Param('id') id: number, @Body() body: EventDto): Promise<EventDto> {
  const event = await this.eventRepository.findOne(id);
  event.name = body.name;
  event.color = body.color;
  event.date = body.date;
  event.location = await this.locationRepository.findOne(body.locationId);
  await this.eventRepository.save(event);
  return event.toDto();
}
```

