2. Create a registration form with fields for name, surname, phone, email, password and confirm password using `TextInput` component of `react-native-paper`. You can use `useState` to maintain the state of the form fields.

3. Add a button to the form to initiate the registration process.

4. When the registration button is pressed, validate the form fields as per your requirements. Verify if password and confirm password are same, and check for any other fields from your validation perspective.

5. If validation succeeds, call the `createUserWithEmailAndPassword` method of the Firebase Authentication API and provide the email and password user enters in the form to store it in firebase.

6. Once a user is successfully registered, store the remaining user data such as name, surname and phone in Firebase Database or Firestore.

Here is sample code to create registration using Firebase with name, surname, phone, password, and confirm password:

```javascript
import React, { useState } from 'react';
import { View } from 'react-native';
import { TextInput, Button } from 'react-native-paper';
import * as firebase from 'firebase';

const RegisterScreen = () => {
  const [name, setName] = useState('');
  const [surname, setSurname] = useState('');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  const registerUser = async () => {
    try {
      if (password !== confirmPassword) {
        alert('Passwords do not match');
        return;
      }
      if (!name || !surname || !phone || !email || !password || !confirmPassword) {
        alert('Please fill all fields');
        return;
      }
      await firebase.auth().createUserWithEmailAndPassword(email, password);
      const currentUser = firebase.auth().currentUser;
      firebase
        .database()
        .ref(`/users/${currentUser.uid}`)
        .set({
          name,
          surname,
          phone,
          email,
        });
    } catch (error) {
      console.log(error);
      alert('Error: ' + error.message);
    }
  };

  return (
    <View>
      <TextInput
        label="Name"
        value={name}
        onChangeText={setName}
        style={{ marginHorizontal: 16, marginVertical: 8 }}
      />
      <TextInput
        label="Surname"
        value={surname}
        onChangeText={setSurname}
        style={{ marginHorizontal: 16, marginVertical: 8 }}
      />
      <TextInput
        label="Phone"
        value={phone}
        onChangeText={setPhone}
        style={{ marginHorizontal: 16, marginVertical: 8 }}
      />
      <TextInput
        label="Email"
        value={email}
        onChangeText={setEmail}
        style={{ marginHorizontal: 16, marginVertical: 8 }}
        keyboardType="email-address"
      />
      <TextInput
        label="Password"
        value={password}
        onChangeText={setPassword}
        style={{ marginHorizontal: 16, marginVertical: 8 }}
        secureTextEntry
      />
      <TextInput
        label="Confirm Password"
        value={confirmPassword}
        onChangeText={setConfirmPassword}
        style={{ marginHorizontal: 16, marginVertical: 8 }}
        secureTextEntry
      />
      <Button
        mode="contained"
        onPress={registerUser}
        style={{ marginHorizontal: 16, marginVertical: 8 }}
      >
        Register
      </Button>
    </View>
  );
};

export default RegisterScreen;
```
