private void showPasscodePrompt() {
    AlertDialog.Builder builder = new AlertDialog.Builder(this);
    builder.setTitle("Enter Passcode");

    // Add a passcode input field to the dialog
    final EditText input = new EditText(this);
    input.setInputType(InputType.TYPE_CLASS_NUMBER | InputType.TYPE_NUMBER_VARIATION_PASSWORD);
    builder.setView(input);

    // Add OK button to the dialog
    builder.setPositiveButton("OK", new DialogInterface.OnClickListener() {
        @Override
        public void onClick(DialogInterface dialog, int which) {
            // Check if passcode is correct
            if (checkPasscode(input.getText().toString())) {
                // Dismiss the dialog and resume the app
                dialog.dismiss();
                resumed = false;
            } else {
                // Show an error message and prompt the user to re-enter the passcode
                Toast.makeText(MyActivity.this, "Incorrect passcode, please try again", Toast.LENGTH_SHORT).show();
                showPasscodePrompt();
            }
        }
    });

    // Add Cancel button to the dialog
    builder.setNegativeButton("Cancel", new DialogInterface.OnClickListener() {
        @Override
        public void onClick(DialogInterface dialog, int which) {
            // Close the app
            finish();
        }
    });

    builder.setCancelable(false);
    builder.show();
}
```

4. Implement `checkPasscode` method which checks if the entered passcode is correct:

```
private boolean checkPasscode(String passcode) {
    // Send a passcode request to the local PHP server and check the response
    // Return true if the passcode is correct, false otherwise
    return passcode.equals("1234"); // Example passcode
}
```

Note: This is just a basic example for demonstrating passcode verification. You should modify the implementation based on your specific requirements.

