	int64_t lastDts[2] = {0, 0};
	int64_t videoLastDts = 0;
	int64_t audioLastDts = 0;

int64_t last_input_pts[2] = {0, 0};
int64_t last_input_dts[2] = {0, 0};
int64_t last_output_pts[2] = {0, 0};
int64_t last_output_dts[2] = {0, 0};

while (load_packet(inputFormatContext, &packet)) {
    int input_stream_index = packet.stream_index;
    if (input_stream_index == videoStreamIndex || input_stream_index == audioStreamIndex) {
        int output_stream_index = input_stream_index == videoStreamIndex ? 0 : 1;
        AVRational input_time_base = inputFormatContext->streams[input_stream_index]->time_base;
        AVRational output_time_base = outputFormatContext->streams[output_stream_index]->time_base;

        packet.pts = std::max(packet.pts, last_input_pts[input_stream_index]);
        packet.dts = std::max(packet.dts, last_input_dts[input_stream_index]);

        last_input_pts[input_stream_index] = packet.pts;
        last_input_dts[input_stream_index] = packet.dts;

        AVPacket outputPacket;
        av_init_packet(&outputPacket);
        av_packet_ref(&outputPacket, &packet);

        int64_t new_pts = av_rescale_q(packet.pts, input_time_base, output_time_base);
        int64_t new_dts = av_rescale_q(packet.dts, input_time_base, output_time_base);

        new_pts = std::max(new_pts, last_output_pts[output_stream_index]);
        new_dts = std::max(new_dts, last_output_dts[output_stream_index]);

        outputPacket.pts = new_pts;
        outputPacket.dts = new_dts;

        last_output_pts[output_stream_index] = new_pts;
        last_output_dts[output_stream_index] = new_dts;

        av_write_frame(outputFormatContext, &outputPacket);
        av_packet_unref(&outputPacket);

        // Sleep for synchronization
        std::this_thread::sleep_until(std::chrono::system_clock::now() +
                                      std::chrono::duration<int64_t, std::micro>(
                                          av_rescale_q(new_pts - last_output_pts[0], output_time_base, {1, 1000000})));
    }

    av_packet_unref(&packet);
}

    av_write_trailer(outputFormatContext);
    avio_closep(&outputFormatContext->pb);

    // Cleaning up.
    avformat_free_context(outputFormatContext);
    avformat_close_input(&inputFormatContext);

    return 0;
}

