#include <errno.h>

#define MAX_EXTENSIONS 6
#define MAX_PATH_LENGTH 256

typedef struct
{
  char *extensions[MAX_EXTENSIONS];
  int maxExtensionCount;
} ExtensionStruct;

ExtensionStruct extensions;
char SourcePath[MAX_PATH_LENGTH], DestinationPath[MAX_PATH_LENGTH];
bool CopyModeSelected;

bool hasExtension(const char *Filename, const char *Extension)
{
  int len = strlen(Filename), ExtensionLength = strlen(Extension);
  if (len <= ExtensionLength)
    return false;
  return strcmp(Filename + len - ExtensionLength, Extension) == 0;
}

bool shouldProcessFile(const char *Filename)
{
  if (extensions.maxExtensionCount == 0)
    return true;
  for (int i = 0; i < extensions.maxExtensionCount; i++)
    if (hasExtension(Filename, extensions.extensions[i]))
      return false;
  return true;
}

void handleError(const char *errorMessage)
{
  perror(errorMessage);
  exit(1);
}

bool checkExtension(const char *filename, const char *extension)
{
  return hasExtension(filename, extension);
}

void copyOrMoveFile(const char *source, const char *destination)
{
  if (CopyModeSelected)
  {
    if (link(source, destination) != 0)
    {
      handleError("Error while copying file");
    }
  }
  else
  {
    if (rename(source, destination) != 0)
    {
      handleError("Error while moving file");
    }
  }
}

void createDirectory(const char *path, mode_t mode)
{
  if (mkdir(path, mode) != 0 && errno != EEXIST)
  {
    handleError("Error while creating directory");
  }
}

void removeFile(const char *path)
{
  if (unlink(path) != 0)
  {
    handleError("Error while removing file");
  }
}

void removeDirectory(const char *path)
{
  DIR *dir = opendir(path);
  if (dir == NULL)
  {
    handleError("Error opening directory");
  }

  struct dirent *entry;
  while ((entry = readdir(dir)) != NULL)
  {
    if (strcmp(entry->d_name, ".") != 0 && strcmp(entry->d_name, "..") != 0)
    {
      char subpath[MAX_PATH_LENGTH];
      snprintf(subpath, MAX_PATH_LENGTH, "%s/%s", path, entry->d_name);

      if (entry->d_type == DT_DIR)
      {
        removeDirectory(subpath);
      }
      else
      {
        removeFile(subpath);
      }
    }
  }

  closedir(dir);
}

int processFile(const char *filePath, const struct stat *sb, int fileType, struct FTW *ftwbuf)
{
  char destinationLocation[MAX_PATH_LENGTH];
  snprintf(destinationLocation, MAX_PATH_LENGTH, "%s/%s", DestinationPath, filePath + strlen(SourcePath) + 1);

  if (fileType == FTW_F)
  {
    if (shouldProcessFile(filePath))
    {
      copyOrMoveFile(filePath, destinationLocation);
    }
  }
  else if (fileType == FTW_D)
  {
    createDirectory(destinationLocation, sb->st_mode);
  }

  return 0;
}

void parseArguments(int argc, char *argv[])
{
  if (argc < 4)
  {
    printf("Usage: ncpmvdir [SourcePath] [DestinationPath] [options]\n");
    printf("Options:\n");
    printf("-cp: Copy mode | -mv: Move mode\n");
    printf("[Extension]: Exclude files with the specified extension\n");
    exit(1);
  }
  else
  {
    if ((strcmp(argv[3], "-cp") == 0) || (strcmp(argv[3], "-CP") == 0))
    {
      CopyModeSelected = true;
    }
    else
    {
      if ((strcmp(argv[3], "-mv") == 0) || (strcmp(argv[3], "-MV") == 0))
      {
        CopyModeSelected = false;
      }
      else
      {
        printf("Option Should be of type -cp or -mv\n");
        exit(1);
      }
    }
    if (argc > 4)
    {
      for (int i = 4; i < argc; i++)
      {
        if (extensions.maxExtensionCount >= MAX_EXTENSIONS)
        {
          printf("Too many extensions specified\n");
          exit(1);
        }
        extensions.extensions[extensions.maxExtensionCount] = argv[i];
        extensions.maxExtensionCount++;
      }
    }
  }

  strncpy(SourcePath, argv[optind], MAX_PATH_LENGTH);
  strncpy(DestinationPath, argv[optind + 1], MAX_PATH_LENGTH);
}

void traverseFileTree(const char *sourcePath)
{
  if (nftw(sourcePath, processFile, 20, FTW_PHYS) != 0)
  {
    handleError("Error while traversing file tree");
  }
}

int main(int argc, char *argv[])
{
  parseArguments(argc, argv);
  traverseFileTree(SourcePath);

  if (!CopyModeSelected)
  {
    removeDirectory(SourcePath);
  }

  return 0;
}



