Here's the updated code with the addition of debouncing and input latching:

```vhdl
LIBRARY ieee;
USE ieee.std_logic_1164.ALL;
USE ieee.numeric_std.ALL;
use ieee.std_logic_unsigned.all;
use STD.textio.all;

entity key_fsm_c is 
    port (clk: in std_logic;
     rst: in std_logic;
     left, right, up, down, center: in std_logic; -- keys
     data_out: out std_logic_vector(31 downto 0):= (others => '0');
     cntr_en: out std_logic;
     cntr_rst: out std_logic;
     cntr_load: out std_logic;
     edit_en_out: out std_logic
     );
end entity;

architecture Behavioral of key_fsm_c is
    type state_type is (idle, start, stop, reset, load, edit, inc_val, dec_val, inc_pos, dec_pos);
    signal c_state, n_state: state_type;

    -- Add these signal definitions for input latching and debouncing
    signal latched_left, latched_right, latched_up, latched_down, latched_center: std_logic;
    signal debounce_counter: integer range 0 to 50000 := 0;
    signal debounce_left, debounce_right, debounce_up, debounce_down, debounce_center: std_logic;
begin
    -- Add this process to implement input debouncing
    debounce_proc: process(clk, rst)
    begin
        if rst = '1' then
            debounce_counter <= 0;
            debounce_left <= '0';
            debounce_right <= '0';
            debounce_up <= '0';
            debounce_down <= '0';
            debounce_center <= '0';
        elsif rising_edge(clk) then
            if debounce_counter < 50000 then
                debounce_counter <= debounce_counter + 1;
            else
                debounce_left <= left;
                debounce_right <= right;
                debounce_up <= up;
                debounce_down <= down;
                debounce_center <= center;
            end if;
        end if;
    end process;

    -- Add this process to implement input latching
    latch_proc: process(clk, rst)
    begin
        if rst = '1' then
            latched_left <= '0';
            latched_right <= '0';
            latched_up <= '0';
            latched_down <= '0';
            latched_center <= '0';
        elsif rising_edge(clk) then
            latched_left <= debounce_left;
            latched_right <= debounce_right;
            latched_up <= debounce_up;
            latched_down <= debounce_down;
            latched_center <= debounce_center;
        end if;
    end process;

    proc_fsm: process(clk, rst) 
        variable position: integer := 0;
        variable act_num: integer := 0;
        variable old_pos: integer := 0;
        variable old_num: integer := 0;
        variable is_begin: integer := 1;
        variable act_frag: std_logic_vector(3 downto 0);
        variable tmp: std_logic_vector(31 downto 0) := (others => '0');
    begin
        if rst = '1' then 
            c_state <= idle;
        elsif rising_edge(clk) then
            c_state <= n_state;
            if (is_begin = 1) then
                cntr_en <= '0';
                is_begin := 0;
            end if;

            case c_state is
                when idle =>
                    n_state <= idle;
                    cntr_rst <= '0';
                    cntr_load <= '0';
                    if latched_right='1' then 
                        n_state <= start;
                    end if;
                    if latched_left = '1' then 
                        n_state <= stop;
                    end if;
                    if latched_down = '1' then 
                        n_state <= reset;
                    end if;
                    if latched_up = '1' then 
                        n_state <= load;
                    end if;
                    if latched_center = '1' then 
                        n_state <= edit;
                    end if;
                when start => 
                    cntr_en <= '1';
                    n_state <= idle;
                when stop => 
                    cntr_en <= '0';
                    n_state <= idle;
                when reset => 
                    cntr_rst <= '1';
                    n_state <= idle;
                when load =>
                    cntr_load <= '1';
                    edit_en_out <= '0';
                    n_state <= idle;
        -- And so on for the other states...
            end case;
            data_out <= tmp;
        end if;
    end process;
end Behavioral;
```

This updated code should improve the stability of the state machine. The latched input signals are used for state transitions, and the debounce process ensures that the transient effects due to switch bouncing are eliminated.

