12. Implement the getClosestGridPoint function:

function getClosestGridPoint(point, gridSize, gridSpacing) {
  // Find the nearest grid vertex to the given point and return it.
  const roundedX = Math.round(point[0] / gridSpacing) * gridSpacing;
  const roundedY = Math.round(point[1] / gridSpacing) * gridSpacing;
  const roundedZ = Math.round(point[2] / gridSpacing) * gridSpacing;

  return [roundedX, roundedY, roundedZ];
}

